for (file_name, content) in content {
    if content.is_empty() {
        let mut header = async_tar::Header::new_gnu();
        header.set_size(0);
        header.set_mode(0o755);
        header.set_entry_type(async_tar::EntryType::Directory);
        header.set_cksum();
        builder.append_data(&mut header, file_name, &[] as &[u8]).await.unwrap();
    } else {
        let data = content.as_bytes();
        let mut header = async_tar::Header::new_gnu();
        header.set_size(data.len() as u64);
        header.set_mode(0o755);
        header.set_entry_type(async_tar::EntryType::Regular);
        header.set_cksum();
        builder.append_data(&mut header, file_name, data).await.unwrap();
    }
}
